     1→// AI Memory + Auto-Fill + Screening Answer Routes
     2→const express = require('express');
     3→const { authMiddleware } = require('../lib/auth');
     4→const memoryService = require('../services/memory-service');
     5→const autofillService = require('../services/autofill-service');
     6→const pool = require('../lib/db');
     7→
     8→const router = express.Router();
     9→
    10→// ============================================================
    11→// AUTO-FILL ENDPOINTS
    12→// ============================================================
    13→
    14→// Get auto-fill data for candidate application forms
    15→router.get('/autofill/candidate', authMiddleware, async (req, res) => {
    16→  try {
    17→    const data = await autofillService.getCandidateAutoFill(req.user.id);
    18→    res.json({ success: true, autofill: data });
    19→  } catch (err) {
    20→    console.error('Candidate autofill error:', err);
    21→    res.status(500).json({ error: 'Failed to get autofill data' });
    22→  }
    23→});
    24→
    25→// Get auto-fill data for recruiter job posting forms
    26→router.get('/autofill/recruiter', authMiddleware, async (req, res) => {
    27→  try {
    28→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
    29→      return res.status(403).json({ error: 'Recruiter access required' });
    30→    }
    31→    const data = await autofillService.getRecruiterAutoFill(req.user.id);
    32→    res.json({ success: true, autofill: data });
    33→  } catch (err) {
    34→    console.error('Recruiter autofill error:', err);
    35→    res.status(500).json({ error: 'Failed to get autofill data' });
    36→  }
    37→});
    38→
    39→// ============================================================
    40→// SCREENING ANSWERS
    41→// ============================================================
    42→
    43→// Get candidate's saved screening answers
    44→router.get('/screening-answers', authMiddleware, async (req, res) => {
    45→  try {
    46→    const result = await pool.query(`
    47→      SELECT sa.id, sa.question_text, sa.answer_text, sa.reuse_count, sa.updated_at,
    48→             qb.category, qb.question_type
    49→      FROM screening_answers sa
    50→      LEFT JOIN question_bank qb ON sa.question_id = qb.id
    51→      WHERE sa.user_id = $1
    52→      ORDER BY sa.reuse_count DESC, sa.updated_at DESC
    53→    `, [req.user.id]);
    54→
    55→    res.json({ success: true, answers: result.rows });
    56→  } catch (err) {
    57→    console.error('Get screening answers error:', err);
    58→    res.status(500).json({ error: 'Failed to get screening answers' });
    59→  }
    60→});
    61→
    62→// Save a screening answer
    63→router.post('/screening-answers', authMiddleware, async (req, res) => {
    64→  try {
    65→    const { question_id, question_text, answer_text, job_id } = req.body;
    66→    if (!question_text || !answer_text) {
    67→      return res.status(400).json({ error: 'question_text and answer_text required' });
    68→    }
    69→
    70→    await autofillService.saveScreeningAnswer(req.user.id, {
    71→      questionId: question_id,
    72→      questionText: question_text,
    73→      answerText: answer_text,
    74→      jobId: job_id
    75→    });
    76→
    77→    // Also extract memory from the answer
    78→    await memoryService.addMemory(req.user.id, {
    79→      type: 'observation',
    80→      key: `screening_${question_text.substring(0, 50).replace(/\s+/g, '_').toLowerCase()}`,
    81→      value: `Q: ${question_text.substring(0, 100)} → A: ${answer_text.substring(0, 200)}`,
    82→      source: 'screening_answer'
    83→    });
    84→
    85→    res.json({ success: true, message: 'Answer saved for future reuse' });
    86→  } catch (err) {
    87→    console.error('Save screening answer error:', err);
    88→    res.status(500).json({ error: 'Failed to save screening answer' });
    89→  }
    90→});
    91→
    92→// ============================================================
    93→// AI MEMORY ENDPOINTS
    94→// ============================================================
    95→
    96→// Get user's AI memory context
    97→router.get('/memories', authMiddleware, async (req, res) => {
    98→  try {
    99→    const { type, limit = 30 } = req.query;
   100→    const memories = await memoryService.getMemories(req.user.id, { type, limit: parseInt(limit) });
   101→    res.json({ success: true, memories });
   102→  } catch (err) {
   103→    console.error('Get memories error:', err);
   104→    res.status(500).json({ error: 'Failed to get memories' });
   105→  }
   106→});
   107→
   108→// Get memory context as AI prompt (for internal use)
   109→router.get('/memory-context', authMiddleware, async (req, res) => {
   110→  try {
   111→    const context = await memoryService.buildMemoryContext(req.user.id);
   112→    res.json({ success: true, context });
