   119→// ============================================================
   120→// RECRUITER QUESTION BANK
   121→// ============================================================
   122→
   123→// Get recruiter's question bank
   124→router.get('/question-bank', authMiddleware, async (req, res) => {
   125→  try {
   126→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   127→      return res.status(403).json({ error: 'Recruiter access required' });
   128→    }
   129→
   130→    const { category } = req.query;
   131→    let query = `
   132→      SELECT id, question_text, question_type, category, options, usage_count, created_at
   133→      FROM question_bank
   134→      WHERE recruiter_id = $1
   135→    `;
   136→    const params = [req.user.id];
   137→
   138→    if (category) {
   139→      query += ` AND category = $2`;
   140→      params.push(category);
   141→    }
   142→
   143→    query += ` ORDER BY usage_count DESC, created_at DESC`;
   144→
   145→    const result = await pool.query(query, params);
   146→    res.json({ success: true, questions: result.rows });
   147→  } catch (err) {
   148→    console.error('Get question bank error:', err);
   149→    res.status(500).json({ error: 'Failed to get question bank' });
   150→  }
   151→});
   152→
   153→// Add question to bank
   154→router.post('/question-bank', authMiddleware, async (req, res) => {
   155→  try {
   156→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   157→      return res.status(403).json({ error: 'Recruiter access required' });
   158→    }
   159→
   160→    const { question_text, question_type = 'text', category = 'general', options = [] } = req.body;
   161→    if (!question_text) {
   162→      return res.status(400).json({ error: 'question_text is required' });
   163→    }
   164→
   165→    const result = await pool.query(`
   166→      INSERT INTO question_bank (question_text, question_type, category, options, recruiter_id, usage_count)
   167→      VALUES ($1, $2, $3, $4, $5, 0)
   168→      ON CONFLICT (recruiter_id, question_text) WHERE recruiter_id IS NOT NULL
   169→      DO UPDATE SET
   170→        question_type = EXCLUDED.question_type,
   171→        category = EXCLUDED.category,
   172→        options = EXCLUDED.options
   173→      RETURNING *
   174→    `, [question_text, question_type, category, JSON.stringify(options), req.user.id]);
   175→
   176→    // Store in memory as recruiter pattern
   177→    await memoryService.addMemory(req.user.id, {
   178→      type: 'recruiter_pattern',
   179→      key: `question_bank_${category}`,
   180→      value: `Added screening question in ${category}: "${question_text.substring(0, 80)}"`,
   181→      source: 'question_bank'
   182→    });
   183→
   184→    res.json({ success: true, question: result.rows[0] });
   185→  } catch (err) {
   186→    console.error('Add question error:', err);
   187→    res.status(500).json({ error: 'Failed to add question' });
   188→  }
   189→});
   190→
   191→// Delete question from bank
   192→router.delete('/question-bank/:id', authMiddleware, async (req, res) => {
   193→  try {
   194→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   195→      return res.status(403).json({ error: 'Recruiter access required' });
   196→    }
   197→
   198→    await pool.query(
   199→      'DELETE FROM question_bank WHERE id = $1 AND recruiter_id = $2',
   200→      [req.params.id, req.user.id]
   201→    );
   202→    res.json({ success: true });
   203→  } catch (err) {
   204→    console.error('Delete question error:', err);
   205→    res.status(500).json({ error: 'Failed to delete question' });
   206→  }
   207→});
   208→
   209→// ============================================================
   210→// RECRUITER PREFERENCES
   211→// ============================================================
   212→
   213→// Get recruiter preferences
   214→router.get('/recruiter-preferences', authMiddleware, async (req, res) => {
   215→  try {
   216→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   217→      return res.status(403).json({ error: 'Recruiter access required' });
   218→    }
   219→
   220→    const result = await pool.query(
   221→      'SELECT * FROM recruiter_preferences WHERE user_id = $1',
   222→      [req.user.id]
