   224→    res.json({ success: true, preferences: result.rows[0] || {} });
   225→  } catch (err) {
   226→    console.error('Get preferences error:', err);
   227→    res.status(500).json({ error: 'Failed to get preferences' });
   228→  }
   229→});
   230→
   231→// Update recruiter preferences
   232→router.put('/recruiter-preferences', authMiddleware, async (req, res) => {
   233→  try {
   234→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   235→      return res.status(403).json({ error: 'Recruiter access required' });
   236→    }
   237→
   238→    await autofillService.updateRecruiterPreferences(req.user.id, req.body);
   239→    res.json({ success: true, message: 'Preferences updated' });
