   245→
   246→// ============================================================
   247→// RECRUITER FEEDBACK ON CANDIDATES
   248→// ============================================================
   249→
   250→// Give feedback on a candidate (thumbs up/down)
   251→router.post('/recruiter-feedback', authMiddleware, async (req, res) => {
   252→  try {
   253→    if (!['recruiter', 'hiring_manager', 'employer', 'admin'].includes(req.user.role)) {
   254→      return res.status(403).json({ error: 'Recruiter access required' });
   255→    }
   256→
   257→    const { candidate_id, job_id, feedback_type, notes } = req.body;
   258→    if (!candidate_id || !feedback_type) {
   259→      return res.status(400).json({ error: 'candidate_id and feedback_type required' });
   260→    }
   261→
   262→    if (!['positive', 'negative', 'neutral'].includes(feedback_type)) {
   263→      return res.status(400).json({ error: 'feedback_type must be positive, negative, or neutral' });
   264→    }
   265→
   266→    const result = await pool.query(`
   267→      INSERT INTO recruiter_feedback (recruiter_id, candidate_id, job_id, feedback_type, notes)
   268→      VALUES ($1, $2, $3, $4, $5)
   269→      ON CONFLICT (recruiter_id, candidate_id, job_id) DO UPDATE SET
   270→        feedback_type = EXCLUDED.feedback_type,
   271→        notes = EXCLUDED.notes,
   272→        created_at = NOW()
   273→      RETURNING *
   274→    `, [req.user.id, candidate_id, job_id || null, feedback_type, notes || null]);
   275→
   276→    // Store in memory
   277→    await memoryService.extractFromRecruiterAction(req.user.id, {
   278→      type: 'candidate_feedback',
   279→      feedback_type,
   280→      job_title: 'position'
   281→    });
   282→
   283→    // Trigger OmniScore recalculation for the candidate
   284→    try {
   285→      const omniscoreService = require('../services/omniscore');
   286→      if (feedback_type === 'positive') {
   287→        await omniscoreService.addBehaviorComponent(candidate_id, 'recruiter_positive_feedback', 8, 10);
   288→      } else if (feedback_type === 'negative') {
   289→        await omniscoreService.addBehaviorComponent(candidate_id, 'recruiter_negative_feedback', -3, 10);
   290→      }
   291→    } catch (e) {
   292→      console.warn('OmniScore recalc after feedback failed:', e.message);
   293→    }
   294→
   295→    res.json({ success: true, feedback: result.rows[0] });
   296→  } catch (err) {
   297→    console.error('Recruiter feedback error:', err);
   298→    res.status(500).json({ error: 'Failed to save feedback' });
   299→  }
   300→});
   301→
   302→// ============================================================
   303→// ENHANCED MATCH RESULTS WITH ALL DIMENSIONS
   304→// ============================================================
   305→
   306→// Get detailed match breakdown for a candidate-job pair
   307→router.get('/match-breakdown/:candidateId/:jobId', authMiddleware, async (req, res) => {
   308→  try {
   309→    const candidateId = parseInt(req.params.candidateId);
   310→    const jobId = parseInt(req.params.jobId);
   311→
   312→    // Auth check: candidates can only see their own
   313→    if (req.user.role === 'candidate' && req.user.id !== candidateId) {
   314→      return res.status(403).json({ error: 'Not authorized' });
   315→    }
   316→
   317→    // Get existing match result
   318→    const matchResult = await pool.query(
   319→      'SELECT * FROM match_results WHERE candidate_id = $1 AND job_id = $2',
   320→      [candidateId, jobId]
   321→    );
   322→
   323→    // Get candidate profile
   324→    const profileResult = await pool.query(`
   325→      SELECT cp.*, u.name, u.email
   326→      FROM users u
   327→      LEFT JOIN candidate_profiles cp ON cp.user_id = u.id
   328→      WHERE u.id = $1
   329→    `, [candidateId]);
   330→    const profile = profileResult.rows[0] || {};
   331→
   332→    // Get job details
   333→    const jobResult = await pool.query('SELECT * FROM jobs WHERE id = $1', [jobId]);
   334→    const job = jobResult.rows[0] || {};
   335→
   336→    // Get candidate skills
   337→    const skillsResult = await pool.query(
   338→      'SELECT skill_name, level FROM candidate_skills WHERE user_id = $1',
   339→      [candidateId]
   340→    );
   341→
   342→    // Get candidate experience
   343→    const expResult = await pool.query(
   344→      'SELECT title, company_name, start_date, end_date, is_current FROM work_experience WHERE user_id = $1 ORDER BY start_date DESC',
   345→      [candidateId]
   346→    );
   347→
   348→    // Get education
   349→    const eduResult = await pool.query(
   350→      'SELECT degree, field_of_study, institution FROM education WHERE user_id = $1',
   351→      [candidateId]
   352→    );
   353→
   354→    // Get OmniScore
   355→    const omniResult = await pool.query(
   356→      'SELECT * FROM omni_scores WHERE user_id = $1',
   357→      [candidateId]
   358→    );
   359→    const omni = omniResult.rows[0] || {};
   360→
   361→    // Get interview scores if any (from interviews table, not interview_analysis)
   362→    const interviewResult = await pool.query(`
   363→      SELECT AVG(i.overall_score) as avg_interview_score, COUNT(*) as interview_count
   364→      FROM interviews i
   365→      WHERE i.user_id = $1 AND i.overall_score IS NOT NULL
   366→    `, [candidateId]);
   367→
   368→    // Get assessment scores if any
   369→    const assessmentResult = await pool.query(`
   370→      SELECT AVG(score) as avg_assessment_score, COUNT(*) as assessment_count
   371→      FROM dynamic_assessments
   372→      WHERE user_id = $1 AND status = 'completed'
   373→    `, [candidateId]);
   374→
   375→    // Calculate dimension scores
   376→    const totalYears = profile.years_experience || 0;
   377→    const jobMinYears = job.min_experience || 0;
   378→    const experienceScore = jobMinYears > 0
   379→      ? Math.min(100, Math.round((totalYears / jobMinYears) * 100))
   380→      : (totalYears > 0 ? 75 : 50);
   381→
   382→    const salaryFit = calculateSalaryFit(profile, job);
   383→    const locationFit = calculateLocationFit(profile, job);
   384→    const educationScore = eduResult.rows.length > 0 ? 70 + Math.min(30, eduResult.rows.length * 10) : 40;
   385→
   386→    const interviewScore = interviewResult.rows[0]?.avg_interview_score
   387→      ? Math.round(interviewResult.rows[0].avg_interview_score * 10)
   388→      : null;
   389→
   390→    const assessmentScore = assessmentResult.rows[0]?.avg_assessment_score
   391→      ? Math.round(assessmentResult.rows[0].avg_assessment_score)
   392→      : null;
   393→
   394→    const match = matchResult.rows[0] || {};
   395→
   396→    const breakdown = {
   397→      overall_score: match.weighted_score || 0,
   398→      match_level: match.match_level || 'none',
   399→      dimensions: {
   400→        skills: {
   401→          score: match.weighted_score ? Math.round((JSON.parse(match.matching_skills || '[]').length / Math.max(1, JSON.parse(match.matching_skills || '[]').length + JSON.parse(match.missing_skills || '[]').length)) * 100) : 50,
   402→          label: 'Skills Match',
   403→          matching: JSON.parse(match.matching_skills || '[]'),
   404→          missing: JSON.parse(match.missing_skills || '[]'),
   405→          weight: 0.30
   406→        },
   407→        experience: {
   408→          score: experienceScore,
   409→          label: 'Experience',
   410→          detail: `${totalYears} years (${jobMinYears > 0 ? `${jobMinYears}+ required` : 'no minimum'})`,
   411→          weight: 0.20
   412→        },
   413→        education: {
   414→          score: educationScore,
   415→          label: 'Education',
   416→          detail: eduResult.rows.map(e => `${e.degree || ''} ${e.field_of_study || ''}`).join(', ') || 'Not specified',
   417→          weight: 0.10
   418→        },
   419→        salary_fit: {
   420→          score: salaryFit,
   421→          label: 'Salary Fit',
   422→          detail: formatSalaryFitDetail(profile, job),
   423→          weight: 0.10
   424→        },
   425→        location: {
   426→          score: locationFit,
   427→          label: 'Location Fit',
   428→          detail: `${profile.location || 'Not specified'} → ${job.location || 'Not specified'}`,
   429→          weight: 0.10
   430→        },
   431→        interview_performance: {
   432→          score: interviewScore,
   433→          label: 'Interview Performance',
   434→          detail: interviewScore !== null
   435→            ? `${interviewResult.rows[0].interview_count} interviews, avg ${interviewScore}%`
   436→            : 'No interviews yet',
   437→          weight: 0.10,
   438→          available: interviewScore !== null
   439→        },
   440→        assessments: {
   441→          score: assessmentScore,
   442→          label: 'Assessments',
   443→          detail: assessmentScore !== null
   444→            ? `${assessmentResult.rows[0].assessment_count} completed, avg ${assessmentScore}%`
   445→            : 'No assessments yet',
   446→          weight: 0.10,
   447→          available: assessmentScore !== null
   448→        }
   449→      },
   450→      omniscore: {
   451→        total: omni.total_score || 300,
   452→        tier: omni.score_tier || 'new',
   453→        interview: omni.interview_score || 0,
   454→        technical: omni.technical_score || 0,
   455→        resume: omni.resume_score || 0,
   456→        behavior: omni.behavior_score || 0
   457→      },
   458→      profile_completeness: autofillService_calculateCompleteness(profile, skillsResult.rows, expResult.rows, eduResult.rows),
   459→      improvement_tips: generateImprovementTips(match, interviewScore, assessmentScore, profile)
   460→    };
   461→
   462→    res.json({ success: true, breakdown });
   463→  } catch (err) {
   464→    console.error('Match breakdown error:', err);
   465→    res.status(500).json({ error: 'Failed to get match breakdown' });
   466→  }
   467→});
   468→
   469→// ============================================================
   470→// OMNISCORE TREND
   471→// ============================================================
   472→
   473→// Get OmniScore trend for charts
   474→router.get('/omniscore-trend', authMiddleware, async (req, res) => {
   475→  try {
   476→    const { days = 30 } = req.query;
   477→
   478→    const result = await pool.query(`
   479→      SELECT new_score as score, change_amount, change_reason, component_type, created_at
   480→      FROM score_history
   481→      WHERE user_id = $1
   482→        AND created_at > NOW() - INTERVAL '1 day' * $2
   483→      ORDER BY created_at ASC
   484→    `, [req.user.id, parseInt(days)]);
   485→
   486→    // Also get current score
   487→    const currentResult = await pool.query(
   488→      'SELECT total_score, score_tier, last_updated FROM omni_scores WHERE user_id = $1',
   489→      [req.user.id]
   490→    );
   491→
   492→    res.json({
   493→      success: true,
   494→      current: currentResult.rows[0] || { total_score: 300, score_tier: 'new' },
   495→      history: result.rows,
   496→      period_days: parseInt(days)
   497→    });
   498→  } catch (err) {
   499→    console.error('OmniScore trend error:', err);
   500→    res.status(500).json({ error: 'Failed to get OmniScore trend' });
   501→  }
   502→});
   503→
   504→// ============================================================
   505→// HELPERS
   506→// ============================================================
   507→
   508→function calculateSalaryFit(profile, job) {
   509→  const candMin = profile.salary_min;
   510→  const candMax = profile.salary_max;
   511→  const jobMin = job.salary_min;
   512→  const jobMax = job.salary_max;
   513→
   514→  if (!candMin && !candMax) return 70; // Unknown = neutral
   515→  if (!jobMin && !jobMax) return 70;
   516→
   517→  const candMid = ((candMin || 0) + (candMax || candMin || 0)) / 2;
   518→  const jobMid = ((jobMin || 0) + (jobMax || jobMin || 0)) / 2;
   519→
   520→  if (jobMid === 0) return 70;
   521→
   522→  const overlap = 1 - Math.abs(candMid - jobMid) / Math.max(candMid, jobMid);
   523→  return Math.max(20, Math.min(100, Math.round(overlap * 100)));
   524→}
   525→
   526→function formatSalaryFitDetail(profile, job) {
